import React, { useEffect, useMemo, useState } from 'react';
import { pondService, sensorService } from '../../services/api';
import '../../styles/dashboard.css';
import '../../styles/technician/technician-layout.css';
import '../../styles/technician/technician-sensors.css';
import { pushToast } from "../../utils/toastBridge";
const emptyForm = {
  pondId: '',
  sensorName: '',
  sensorType: '',
  serialNumber: '',
  status: 'ACTIVE'
};
const TechnicianSensors = () => {
  const [sensors, setSensors] = useState([]);
  const [ponds, setPonds] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [pondFilter, setPondFilter] = useState('ALL');
  const [typeFilter, setTypeFilter] = useState('ALL');
  const [statusFilter, setStatusFilter] = useState('ALL');
  const [pageSize, setPageSize] = useState(10);
  const [currentPage, setCurrentPage] = useState(1);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const error = null;
  const [showModal, setShowModal] = useState(false);
  const [form, setForm] = useState(emptyForm);
  const [editingId, setEditingId] = useState(null);
  useEffect(() => {
    fetchData();
  }, []);
  const fetchData = async () => {
    try {
      setLoading(true);
      const [sensorRes, pondRes] = await Promise.all([sensorService.getAllSensors(), pondService.getAllPonds()]);
      setSensors(sensorRes?.data?.data || []);
      setPonds(pondRes?.data?.data || []);
    } catch (err) {
      pushToast({
        title: "Thất bại",
        message: err?.response?.data?.message || 'KhÃ´ng táº£i Ä‘Æ°á»£c dá»¯ liá»‡u cáº£m biáº¿n',
        type: "error"
      });
    } finally {
      setLoading(false);
    }
  };
  const pondOptions = useMemo(() => ponds, [ponds]);
  const normalizeType = type => String(type || '').trim().toLowerCase();
  const normalizeStatus = status => {
    const value = String(status || '').trim().toUpperCase();
    if (['ACTIVE', 'HOAT_DONG', 'ONLINE'].includes(value)) return 'ACTIVE';
    if (['INACTIVE', 'OFFLINE', 'NGOAI_TUYEN'].includes(value)) return 'INACTIVE';
    return value || 'INACTIVE';
  };
  const getStatusLabel = status => {
    switch (normalizeStatus(status)) {
      case 'ACTIVE':
        return 'Hoáº¡t Ä‘á»™ng';
      case 'INACTIVE':
        return 'Ngoáº¡i tuyáº¿n';
      default:
        return 'Ngoáº¡i tuyáº¿n';
    }
  };
  const getTypeLabel = sensorType => {
    switch (normalizeType(sensorType)) {
      case 'ph':
        return 'Äá»™ pH';
      case 'temperature':
        return 'Nhiá»‡t Ä‘á»™ nÆ°á»›c';
      case 'dissolved oxygen':
        return 'Oxy hÃ²a tan';
      case 'salinity':
        return 'Äá»™ máº·n';
      case 'water level':
      case 'turbidity':
        return 'Äá»™ Ä‘á»¥c';
      default:
        return sensorType || '-';
    }
  };
  const getSensorBadge = sensorType => {
    switch (normalizeType(sensorType)) {
      case 'ph':
        return 'pH';
      case 'temperature':
        return 'Â°C';
      case 'dissolved oxygen':
        return 'O2';
      case 'salinity':
        return 'Na';
      case 'water level':
      case 'turbidity':
        return 'NTU';
      default:
        return 'SN';
    }
  };
  const getDisplayValue = sensor => {
    const value = sensor.current_value;
    if (value === null || value === undefined || Number.isNaN(Number(value))) return '-';
    const num = Number(value);
    const type = normalizeType(sensor.sensor_type);
    if (type === 'temperature') return `${num.toFixed(1)}Â°C`;
    if (type === 'dissolved oxygen') return `${num.toFixed(1)} mg/L`;
    if (type === 'ph') return `${num.toFixed(1)} pH`;
    if (type === 'salinity') return `${num.toFixed(1)} ppt`;
    if (type === 'water level' || type === 'turbidity') return `${num.toFixed(1)} NTU`;
    return `${num.toFixed(1)}`;
  };
  const formatDateTime = raw => {
    if (!raw) return '-';
    const d = new Date(raw);
    if (Number.isNaN(d.getTime())) return '-';
    return d.toLocaleString('vi-VN', {
      hour: '2-digit',
      minute: '2-digit',
      day: '2-digit',
      month: '2-digit',
      year: 'numeric'
    });
  };
  const resetToFirstPage = () => {
    setCurrentPage(1);
  };
  const filteredSensors = useMemo(() => {
    return sensors.filter(sensor => {
      const normalizedSearch = searchTerm.trim().toLowerCase();
      const searchMatched = !normalizedSearch || String(sensor.sensor_name || '').toLowerCase().includes(normalizedSearch) || String(sensor.serial_number || '').toLowerCase().includes(normalizedSearch) || String(sensor.sensor_id || '').toLowerCase().includes(normalizedSearch);
      const sensorPondId = String(sensor.pond_id || '');
      const pondMatched = pondFilter === 'ALL' || String(pondFilter) === sensorPondId;
      const sensorType = normalizeType(sensor.sensor_type);
